#include<bits/stdc++.h>
using namespace std;
int a[100001];
int bz[1000005],flag=0;  
int h[1000005];   
void bfs(int m,int n,int s)
{
	int t=0,w=1; 
    h[w]=m;    
    int k=1;
    while(t<w)
	{
			t++;
        	if(h[t]==n)
			{
				flag=1;
           	 	break;
        	}
        	int x=h[t]+a[h[t]];
        	if(x<=1000000&&bz[x]==0)
			{
				w++;
         	   	h[w]=x; 
        	    bz[x]=bz[h[t]]+1;
        	}
        	x=h[t]-a[h[t]];
       	 	if(x>=1&&bz[x]==0)
			{
				w++;
          	 	 h[w]=x;   
         	   bz[x]=bz[h[t]]+1;
        	}
    }
    return ;
}
int main()
{
    int s,m,n;
    scanf("%d%d%d",&s,&m,&n);
    for(int i=1;i<=s;i++)
    {
    	scanf("%d",&a[i]);
	}
    for(int i=0;i<=1000000;i++)
	{
        bz[i]=0;
    }
    bfs(m,n,s);
    if(flag==0)
    {
    	printf("-1");
	}
	else
	{
		printf("%d",bz[n]);
	}
    return 0;
}
